INSERT INTO moments (id, user_id, content, images_json, video_url, location, like_count, comment_count, is_anonymous, anonymous_name, created_at, share_count) VALUES ('40ebb916-c52e-4a36-932e-894f6102562a', '1c3cb358-9924-49f2-997e-a7304347c19c', '111', '["data:image/jpeg;base64,"]', '', '', 0, 0, true, '微风K361', '2026-05-16T14:34:08.328Z', 0), ('7543d166-b835-4d1c-9f8d-7b7709aa85a5', '1c3cb358-9924-49f2-997e-a7304347c19c', '爱心', '["data:image/jpeg;base64,"]', '', '北京', 0, 0, false, '', '2026-05-16T14:34:26.427Z', 0), ('a1cf8678-a72c-4b37-b6ef-3b9d353afcb4', '5af2cb7d-8c81-458b-be56-b8696c7aff38', '今天阳光真好，和闺蜜一起去了网红咖啡店拍照打卡。这家的拿铁拉花超美，味道也很棒！推荐给喜欢拍照的小姐姐们~', '["https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=400&h=400&fit=crop"]', '', '成都', 0, 0, false, '', '2026-05-16T14:35:55.544Z', 0), ('4d47c80e-376c-460d-bd6a-77b02bf83714', '9ecd90fc-63cd-4351-8a97-4f0c85a72a17', '周末瑜伽课后拍的，感觉整个人都放松下来了。瑜伽真的能让心情变好，推荐大家试试！', '["https://images.unsplash.com/photo-1517841905240-472988babdf9?w=400&h=400&fit=crop"]', '', '杭州', 0, 0, false, '', '2026-05-16T14:35:55.548Z', 0), ('0a3c60df-4d97-47fa-8c40-78f3944fb1e4', '5c638389-eedc-4643-8a89-11cab91b4ac2', '健身三个月对比图，坚持真的会有回报的！从最开始跑两步就喘，到现在能跑完5公里，感觉自己棒棒的~', '["https://images.unsplash.com/photo-1524504388940-b1c1722653e1?w=400&h=400&fit=crop"]', '', '深圳', 0, 0, false, '', '2026-05-16T14:35:55.549Z', 0), ('c85c45dc-101e-4496-a5a2-c879e605f8d0', '88cea422-7bdd-474b-ba65-ef3423053990', '今天的穿搭分享，春天就是要穿亮色系呀！这件黄色连衣裙是在韩国代购的，很显白哦~', '["https://images.unsplash.com/photo-1488426862026-3ee34a7d66df?w=400&h=400&fit=crop"]', '', '南京', 0, 0, false, '', '2026-05-16T14:35:55.550Z', 0), ('812180e7-8c89-49a6-8f18-51ab7470ce9a', 'abe7caee-ab15-4079-b8d8-b3856b3f037b', '刚做完头发护理，给大家看看对比效果。养发真的很重要，头发顺滑了整个人的气质都提升了！', '["https://images.unsplash.com/photo-1534528741775-53994a69daeb?w=400&h=400&fit=crop"]', '', '上海', 0, 0, false, '', '2026-05-16T14:35:55.551Z', 0), ('9bb1b60d-55a6-45d3-bd85-78f421f0e2a2', '35bc52c3-7f2c-4131-8d99-65423db1ecad', '今天完成了项目代码review，学到了很多优化技巧。团队协作真的很重要，每个人都有自己的长处。', '[]', '', '北京', 0, 0, false, '', '2026-05-16T14:35:55.553Z', 0), ('9ca6887c-2b13-4633-bee3-724b8c43a134', '442dc7b9-a427-498b-a636-34c51c180d5c', '今天学生们的期末演出圆满结束，看着他们从不敢上台到自信表演，真的很有成就感。当老师最大的幸福就是这个时刻。', '[]', '', '武汉', 0, 0, false, '', '2026-05-16T14:35:55.554Z', 0), ('14e94758-5daa-42c3-868d-c4617200dcf0', '0cae5e9d-87b8-48a5-9b10-9b0425ff0b30', '周末读了《原子习惯》这本书，感触很深。想要改变人生，就要从每天的小习惯开始。分享给大家：习惯改变命运。', '[]', '', '北京', 0, 0, false, '', '2026-05-16T14:35:55.555Z', 0), ('b7885772-9d2d-437e-8eba-a1ac9e241ad1', '023b10ec-4361-437f-a310-cf26e750bd88', '今天在法院开庭，案子终于有了结果。当律师最有成就感的时刻就是为当事人争取到合法权益。继续努力！', '[]', '', '深圳', 0, 0, false, '', '2026-05-16T14:35:55.556Z', 0), ('f1b8eae3-3f8b-4a91-8292-092d8cf24e20', '69ab5a52-9883-4dcb-966c-7f5409d819f0', '今天收到小患者的家长送来的锦旗，医者仁心，这份认可比什么都重要。继续做一个有温度的儿科医生！', '[]', '', '青岛', 0, 0, false, '', '2026-05-16T14:35:55.556Z', 0), ('9c365878-4578-4cbd-87d8-e8ec9ec01357', '1c3cb358-9924-49f2-997e-a7304347c19c', '天气很好', '[]', '', '', 0, 0, false, '', '2026-05-16T22:28:39.977Z', 0), ('dce103c4-1178-497d-ac03-ba11efad0080', '442dc7b9-a427-498b-a636-34c51c180d5c', '哈哈哈，太开心了', '["data:image/jpeg;base64,"]', '', '', 0, 0, false, '', '2026-05-16T22:31:40.873Z', 0), ('91b31f1f-8d80-4927-a1e6-87171842e310', '442dc7b9-a427-498b-a636-34c51c180d5c', '致敬', '["data:image/jpeg;base64,"]', '', '', 0, 0, false, '', '2026-05-16T22:32:04.076Z', 0), ('735b70dd-8b67-4c5c-b8a6-af4b4e9b8059', '442dc7b9-a427-498b-a636-34c51c180d5c', '来找我聊天呀', '[]', '', '', 0, 0, false, '', '2026-05-16T22:32:21.848Z', 0), ('a0000000-0000-0000-0000-000000000001', '1c3cb358-9924-49f2-997e-a7304347c19c', '测试动态', '[]', '', '', 0, 0, false, '', '2026-05-17T07:47:02.819Z', 0);
